function AStarSearch(start, goal, h):
 // Initialize
 OPEN = priority queue ordered by f(n)
 CLOSED = empty set

 node = start
 node.g = 0
 node.h = h(start, goal)
 node.f = node.g + node.h
 node.parent = null

 INSERT node INTO OPEN

 while OPEN is not empty:
 // Get node with lowest f-value
 node = POP from OPEN

 // Check if goal reached
 if node == goal:
 return Path(node) // Backtrack using parent

 // Add to CLOSED
 INSERT node INTO CLOSED

 // Expand successors
 for each successor of node:
 if successor in CLOSED:
 continue

 g_cost = node.g + cost(node, successor)

 // Check if better path found
 if successor not in OPEN:
 successor.g = g_cost
 successor.h = h(successor, goal)
 successor.f = successor.g + successor.h
 successor.parent = node
 INSERT successor INTO OPEN
 else if g_cost < successor.g:
 // Found better path
 successor.g = g_cost
 successor.f = successor.g + successor.h
 successor.parent = node
 // Update position in priority queue
 REINSERT successor INTO OPEN

 return failure // No solution found

function GreedyBestFirstSearch(start, goal, h):
 // Initialize
 OPEN = priority queue ordered by h(n)
 CLOSED = empty set

 node = start
 node.h = h(node, goal)
 node.parent = null

 INSERT node INTO OPEN

 while OPEN is not empty:
 // Get node with lowest heuristic value
 node = POP from OPEN

 // Check if goal reached
 if node == goal:
 return Path(node)

 // Add to CLOSED
 INSERT node INTO CLOSED

 // Expand successors
 for each successor of node:
 if successor in CLOSED:
 continue

 successor.h = h(successor, goal)
 successor.parent = node

 INSERT successor INTO OPEN

 return failure

function RBFS(node, f_limit):
 // Check if goal
 if node == goal:
 return node, 0

 // Get successors
 successors = Expand(node)

 if successors is empty:
 return null, infinity

 // Initialize with infinity except for best
 for each s in successors:
 s.f = max(s.g + s.h, node.f)

 // Loop through successors
 while true:
 // Find best successor
 best = node with lowest f in successors
 best_f = best.f

 // Check if worse than parent
 if best_f > f_limit:
 return null, best_f

 // Check second-best for backtracking
 alternative = second lowest f in successors

 // Recurse with new limit
 result, best_f = RBFS(best, min(f_limit, alternative))

 // Update this node's f for parent
 best.f = best_f

 if result != null:
 return result, best_f

 return RBFS(start, infinity)

function IDAStar(start, goal, h):
 // Initial bound is heuristic of start
 bound = h(start, goal)

 while true:
 // Search with current bound
 result, t = Search(start, 0, bound, goal, h)

 if result != failure:
 return result // Found solution

 if t == infinity:
 return failure // No solution exists

 // Next bound is minimum f-value that exceeded
 bound = t


function Search(node, g, bound, goal, h):
 f = g + h(node, goal)

 // f exceeded current bound
 if f > bound:
 return null, f

 // Found goal
 if node == goal:
 return node, bound

 min = infinity

 // Expand all successors
 for each successor of node:
 result, t = Search(successor, g + cost(node, successor), bound, goal, h)

 if result != null:
 return result, bound

 min = min(min, t)

 return null, min
